//! Utility crate for the crack harness providing common utilities.
//!
//! This crate re-exports `n0_future` and provides common utilities for
/// working with time, randomness, async task spawning, and sleeping
/// in the crack harness environment.
//!
//! # Features
//!
//! - **Time utilities**: `get_timestamp_now_ms` for current timestamp in milliseconds
//! - **Async utilities**: `spawn` for spawning futures on the `n0_future` executor,
//!   `sleep_ms` for async sleeping
//! - **Randomness**: `random_u32` for generating random `u32` values using `nanorand`
//!
//! # Features
//!
//! - `std` (enabled by default): Enables std support
//! - `wasm`: Enables WASM support (enabled by default on wasm32 targets)

pub use n0_future;

/// Returns the current UTC timestamp in milliseconds since the Unix epoch.
///
/// Uses `chrono::offset::Utc::now()` to get the current time and converts
/// it to milliseconds since the Unix epoch (January 1, 1970 00:00:00 UTC).
///
/// # Returns
///
/// Current timestamp in milliseconds since Unix epoch as `i64`.
///
/// # Example
///
/// ```rust
/// let ts = _crack_utils::get_timestamp_now_ms();
/// assert!(ts > 0);
/// ```
pub fn get_timestamp_now_ms() -> i64 {
    chrono::offset::Utc::now().timestamp_millis()
}

/// Spawns a future on the `n0_future` task executor.
///
/// This is a convenience wrapper around `n0_future::task::spawn` that
/// spawns a `Send + 'static` future onto the `n0_future` task executor
/// and returns a `JoinHandle` for awaiting its result.
///
/// # Type Parameters
///
/// * `F` - A future type that implements `Future + Send + 'static`
/// * `F::Output` - The output type of the future, must implement `Send + 'static`
///
/// # Arguments
///
/// * `f` - The future to spawn
///
/// # Returns
///
/// A `JoinHandle<F::Output>` that can be awaited to get the future's result.
///
/// # Example
///
/// ```rust,ignore
/// let handle = _crack_utils::spawn(async {
///     // Do some async work
///     42
/// });
/// let result = handle.await;
/// assert_eq!(result, 42);
/// ```
pub fn spawn<F>(f: F) -> n0_future::task::JoinHandle<F::Output>
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    n0_future::task::spawn(f)
}

/// Generates a random `u32` using `nanorand`.
///
/// Uses `rand::random()` which internally uses `nanorand`'s `WyRand`
/// for fast, high-quality random number generation.
///
/// # Returns
///
/// A random `u32` value.
///
/// # Example
///
/// ```rust
/// let a = _crack_utils::random_u32();
/// let b = _crack_utils::random_u32();
/// assert_ne!(a, b); // Extremely likely to be different
/// ```
pub fn random_u32() -> u32 {
    ::rand::random()
}

/// Sleeps asynchronously for the specified number of milliseconds.
///
/// Uses `n0_future::time::sleep` to yield control for the specified duration.
/// The sleep duration is converted from milliseconds to a `std::time::Duration`.
///
/// # Arguments
///
/// * `dt_ms` - Duration to sleep in milliseconds (as `u32`)
///
/// # Example
///
/// ```rust,ignore
/// let start = _crack_utils::get_timestamp_now_ms();
/// _crack_utils::sleep_ms(100).await;
/// let elapsed = _crack_utils::get_timestamp_now_ms() - start;
/// assert!(elapsed >= 90); // Allow some slack
/// ```
pub async fn sleep_ms(dt_ms: u32) {
    let _sleep = n0_future::time::sleep(std::time::Duration::from_millis(dt_ms as u64)).await;
}

#[cfg(test)]
mod tests {
    #[cfg(target_arch = "wasm32")]
    use wasm_bindgen_test::wasm_bindgen_test as test;
    use super::*;

    #[test]
    fn smoke_get_timestamp_now_ms() {
        let ts = get_timestamp_now_ms();
        assert!(ts > 0, "timestamp should be positive, got {ts}");
    }

    #[test]
    fn smoke_random_u32() {
        // Two draws should (overwhelmingly) differ; guards against a stubbed RNG.
        assert_ne!(random_u32(), random_u32());
    }

    async fn sleep_ms_body() {
        let before = get_timestamp_now_ms();
        sleep_ms(20).await;
        let elapsed = get_timestamp_now_ms() - before;
        assert!(elapsed >= 15, "sleep_ms(20) returned after {elapsed}ms");
    }

    #[cfg(not(target_arch = "wasm32"))]
    #[tokio::test]
    async fn smoke_sleep_ms() {
        sleep_ms_body().await;
    }

    #[cfg(target_arch = "wasm32")]
    #[wasm_bindgen_test::wasm_bindgen_test]
    async fn smoke_sleep_ms() {
        sleep_ms_body().await;
    }
}
EOF

